PRAGMA journal_mode = WAL;
PRAGMA foreign_keys = ON;

CREATE TABLE IF NOT EXISTS users (id TEXT PRIMARY KEY, email TEXT NOT NULL, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS projects (id TEXT PRIMARY KEY, user_id TEXT NOT NULL REFERENCES users(id), name TEXT NOT NULL, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS target_websites (id TEXT PRIMARY KEY, project_id TEXT NOT NULL REFERENCES projects(id), canonical_url TEXT NOT NULL, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS rehearsals (id TEXT PRIMARY KEY, project_id TEXT NOT NULL REFERENCES projects(id), target_website_id TEXT NOT NULL REFERENCES target_websites(id), source_rehearsal_id TEXT REFERENCES rehearsals(id), status TEXT NOT NULL, score INTEGER, inconclusive_reason TEXT, public_token_hash TEXT, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS rehearsal_configurations (id TEXT PRIMARY KEY, rehearsal_id TEXT NOT NULL UNIQUE REFERENCES rehearsals(id), version INTEGER NOT NULL, snapshot_json TEXT NOT NULL, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS personas (id TEXT PRIMARY KEY, project_id TEXT NOT NULL REFERENCES projects(id), version INTEGER NOT NULL, snapshot_json TEXT NOT NULL, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS scenarios (id TEXT PRIMARY KEY, rehearsal_id TEXT NOT NULL REFERENCES rehearsals(id), persona_id TEXT NOT NULL REFERENCES personas(id), stable_key TEXT NOT NULL, snapshot_json TEXT NOT NULL, created_at TEXT NOT NULL, updated_at TEXT NOT NULL, UNIQUE(rehearsal_id, stable_key));
CREATE TABLE IF NOT EXISTS browser_sessions (id TEXT PRIMARY KEY, rehearsal_id TEXT NOT NULL REFERENCES rehearsals(id), scenario_id TEXT NOT NULL REFERENCES scenarios(id), attempt INTEGER NOT NULL DEFAULT 1, status TEXT NOT NULL, outcome TEXT, termination_reason TEXT, deterministic_completed INTEGER NOT NULL DEFAULT 0, perceived_completed INTEGER NOT NULL DEFAULT 0, started_at TEXT, completed_at TEXT, created_at TEXT NOT NULL, updated_at TEXT NOT NULL, UNIQUE(scenario_id, attempt));
CREATE TABLE IF NOT EXISTS session_steps (id TEXT PRIMARY KEY, session_id TEXT NOT NULL REFERENCES browser_sessions(id), sequence INTEGER NOT NULL, timestamp TEXT NOT NULL, current_url TEXT NOT NULL, action_type TEXT NOT NULL, target_description TEXT, result TEXT NOT NULL, screenshot_ref TEXT, observation TEXT, failure_code TEXT, created_at TEXT NOT NULL, updated_at TEXT NOT NULL, UNIQUE(session_id, sequence));
CREATE TABLE IF NOT EXISTS browser_artifacts (id TEXT PRIMARY KEY, session_id TEXT NOT NULL REFERENCES browser_sessions(id), step_id TEXT REFERENCES session_steps(id), kind TEXT NOT NULL, path TEXT NOT NULL, mime_type TEXT NOT NULL, sha256 TEXT NOT NULL, is_public_safe INTEGER NOT NULL DEFAULT 0, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS console_events (id TEXT PRIMARY KEY, session_id TEXT NOT NULL REFERENCES browser_sessions(id), step_id TEXT REFERENCES session_steps(id), level TEXT NOT NULL, message TEXT NOT NULL, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS network_events (id TEXT PRIMARY KEY, session_id TEXT NOT NULL REFERENCES browser_sessions(id), step_id TEXT REFERENCES session_steps(id), url TEXT NOT NULL, method TEXT NOT NULL, status INTEGER, error_text TEXT, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS findings (id TEXT PRIMARY KEY, rehearsal_id TEXT NOT NULL REFERENCES rehearsals(id), fingerprint TEXT NOT NULL, title TEXT NOT NULL, category TEXT NOT NULL, severity TEXT NOT NULL, confidence TEXT NOT NULL, evidence_type TEXT NOT NULL, affected_url TEXT NOT NULL, device_class TEXT NOT NULL, observed_behavior TEXT NOT NULL, ai_interpretation TEXT, recommended_fix TEXT NOT NULL, status TEXT NOT NULL DEFAULT 'open', created_at TEXT NOT NULL, updated_at TEXT NOT NULL, UNIQUE(rehearsal_id, fingerprint));
CREATE TABLE IF NOT EXISTS finding_occurrences (id TEXT PRIMARY KEY, finding_id TEXT NOT NULL REFERENCES findings(id), session_id TEXT NOT NULL REFERENCES browser_sessions(id), step_id TEXT REFERENCES session_steps(id), screenshot_ref TEXT, reproduction_json TEXT NOT NULL, created_at TEXT NOT NULL, updated_at TEXT NOT NULL, UNIQUE(finding_id, session_id, step_id));
CREATE TABLE IF NOT EXISTS recommendations (id TEXT PRIMARY KEY, finding_id TEXT NOT NULL UNIQUE REFERENCES findings(id), body TEXT NOT NULL, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS comparisons (id TEXT PRIMARY KEY, project_id TEXT NOT NULL REFERENCES projects(id), baseline_rehearsal_id TEXT NOT NULL REFERENCES rehearsals(id), candidate_rehearsal_id TEXT NOT NULL REFERENCES rehearsals(id), snapshot_json TEXT NOT NULL, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS jobs (id TEXT PRIMARY KEY, rehearsal_id TEXT NOT NULL REFERENCES rehearsals(id), state TEXT NOT NULL, progress INTEGER NOT NULL DEFAULT 0, attempts INTEGER NOT NULL DEFAULT 0, max_attempts INTEGER NOT NULL DEFAULT 2, locked_at TEXT, lock_token TEXT, heartbeat_at TEXT, run_at TEXT NOT NULL, error_code TEXT, created_at TEXT NOT NULL, updated_at TEXT NOT NULL, UNIQUE(rehearsal_id));
CREATE TABLE IF NOT EXISTS audit_events (id TEXT PRIMARY KEY, user_id TEXT REFERENCES users(id), project_id TEXT REFERENCES projects(id), rehearsal_id TEXT REFERENCES rehearsals(id), event_type TEXT NOT NULL, metadata_json TEXT NOT NULL, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE INDEX IF NOT EXISTS idx_jobs_claim ON jobs(state, run_at, locked_at);
CREATE INDEX IF NOT EXISTS idx_sessions_rehearsal ON browser_sessions(rehearsal_id);
CREATE INDEX IF NOT EXISTS idx_findings_rehearsal ON findings(rehearsal_id);
